async (page) => {
  // Navigate east to Herby Mc. Herb at (333,281) - we're south of the cliff now
  const r1 = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 315, y: 265});
  await page.waitForTimeout(4000);
  const pos1 = await page.evaluate(() => {const g=window.__latestGameState; return {x:g.player_position.x,y:g.player_position.y,hp:g.player_stats.hp};});

  const r2 = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 333, y: 281});
  await page.waitForTimeout(6000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
