async (page) => {
  // Click Herby Mc. Herb entity E11 to walk adjacent
  const result = await page.evaluate((label) => JSON.stringify(window.__clickEntity(label)), 'E11');
  await page.waitForTimeout(6000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const herby = parsed.nearby_entities.find(e => e.name === 'Herby Mc. Herb');
  return JSON.stringify({pos: parsed.player_position, hp: parsed.player_stats.hp, herby_dist: herby?.distance, herby_on_screen: herby?.on_screen});
}

async (page) => {
  // Check if respawn button is visible and click it
  const uiState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {is_dead: gs.ui_state.is_dead, respawn_btn: gs.ui_state.respawn_button_visible};
  });

  if (uiState.is_dead || uiState.respawn_btn) {
    await page.evaluate(() => {
      const btn = document.getElementById('respawn');
      if (btn) btn.click();
    });
    await page.waitForTimeout(3000);
  }

  const pos = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {x: gs.player_position.x, y: gs.player_position.y, hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp};
  });
  return JSON.stringify(pos);
}

async (page) => {
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  // Set attack style to Hack (0) after warp
  await page.evaluate(() => window.game.player.setAttackStyle(0));

  const pos = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {x: gs.player_position.x, y: gs.player_position.y, hp: gs.player_stats.hp, equipment: gs.equipment};
  });
  return JSON.stringify(pos);
}

